INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (2, '两球落后上演绝地大逆转！阿根廷击败埃及晋级世界杯八强_运动家_澎湃新闻-The Paper', 14.359, 65, 0, '2026-06-22 15:55:41', '2026-07-12 15:29:35', '2026-07-12 12:00:00', 'mid_high', 'growth', 0.9, 0.05, 0.9, 0.05, 0.0, '当前事件报道数量持续增加，公众关注度快速提升，处于成长期。', 0.409, 0.409, 0.182, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '第19分钟，塔利亚菲科在禁区内被绊倒，阿根廷队获得点球机会，然而梅西主罚的点球被埃及门将舒贝尔扑出，阿根廷队错失扳平比分的良机。八分之一决赛面对另一支非洲球队埃及，阿根廷队更是一度被逼到悬崖边，在两球落后的情况下，依靠比赛最后十几分钟里的连入三球才完成大逆转晋级，梅西也忍不住在赛后激动落泪。新华社美国亚特兰大7月7日电（记者王恒志 董意行）在0:2落后的绝境中，在梅西上半场罚丢点球的情况下，卫冕冠军阿根廷队在比赛最后阶段的13分钟内连入三球，神奇逆转埃及队，晋级美加墨世界杯八强。', '埃及、瑞士、美加墨', '混合团体世界杯：国乒轻取埃及队收获两连胜--文旅·体育--人民网。', '["斯卡", "洛尼", "萨拉", "阿尔瓦雷", "迈阿密"]', '{"credibility_score": 0.595, "official_ratio": 0.508, "verified_ratio": 0.646, "plain_user_ratio": 0.354, "verification_dist": {"官方平台": 0.508, "普通用户": 0.354, "认证个人": 0.108, "认证机构": 0.015, "头部认证个人": 0.015}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "人民网", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-06-22T15:55:41", "influence": 0.0, "title": "世界杯播报丨姆巴佩将迎国家队里程碑 梅西能否创造新历史--文旅·体育--人民网"}, {"role": "首次大V发声", "author": "参考消息", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-06-28T12:49:57", "influence": 2662.9, "title": "【外媒：#伊朗队队长怒斥国际足联#】据西班牙《先锋报》网站6月27日报道，在美加"}, {"role": "传播高峰", "author": "新华社", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-08T02:12:57", "influence": 3165.3, "title": "#阿根廷队让二追三#【梅西传射创纪录 阿根廷绝地逆转埃及进世界杯八强】#阿根廷绝"}, {"role": "初始爆料", "author": "丁小东", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-08T10:19:38", "influence": 0.6, "title": "上半场埃及队压着阿根廷打。开场第14分钟，埃及队头数破门。埃及队1：0领先阿根廷"}], "top_influencers": [{"author": "新华社", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-08T02:12:57", "influence": 3165.3, "repost_count": 618, "like_count": 7986, "comment_count": 303, "title": "#阿根廷队让二追三#【梅西传射创纪录 阿根廷绝地逆转埃及进世界杯八强】#阿根廷绝"}, {"author": "参考消息", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-06-28T12:49:57", "influence": 2662.9, "repost_count": 297, "like_count": 6548, "comment_count": 803, "title": "【外媒：#伊朗队队长怒斥国际足联#】据西班牙《先锋报》网站6月27日报道，在美加"}, {"author": "DeMess1Cafe", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-12T12:14:19", "influence": 2076.3, "repost_count": 532, "like_count": 4691, "comment_count": 274, "title": "斯卡赛后情绪有点崩 我都不忍心了，都不容易[捂嘴哭] ——记者：“在阿根廷的时候"}, {"author": "Super Mario", "platform": "知乎", "verification_type": "认证个人", "publish_time": "2026-07-10T19:23:50", "influence": 259.3, "repost_count": 0, "like_count": 586, "comment_count": 167, "title": "我做为一个梅西的球迷，看完对佛得角和埃及的比赛，已经对阿根廷夺冠不抱有任何希望。"}, {"author": "文123", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-08T16:49:59", "influence": 226.3, "repost_count": 0, "like_count": 446, "comment_count": 185, "title": "埃及前面70分钟踢的挺好，最后输了大家也会夸他踢得好，就像佛得角。虽败犹荣，下届"}], "platform_chain": {"nodes": [{"name": "人民网", "count": 7, "first_seen": "2026-06-22T15:55:41"}, {"name": "微博", "count": 7, "first_seen": "2026-06-28T12:49:57"}, {"name": "澎湃新闻", "count": 10, "first_seen": "2026-07-08T02:05:00"}, {"name": "知乎", "count": 27, "first_seen": "2026-07-08T10:19:38"}, {"name": "新浪新闻", "count": 13, "first_seen": "2026-07-10T17:17:49.000001"}], "links": [{"source": "人民网", "target": "微博", "value": 7}, {"source": "微博", "target": "澎湃新闻", "value": 10}, {"source": "澎湃新闻", "target": "知乎", "value": 27}, {"source": "知乎", "target": "新浪新闻", "value": 13}]}}', '2026-07-13 19:10:32', '2026-07-13 19:10:32');
