INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (5, '指责主裁双标，埃及足协就争议判罚向国际足联提出申诉_运动家_澎湃新闻-The Paper', 9.94, 75, 0, '2026-07-08 01:34:23', '2026-07-12 22:24:48', '2026-07-08 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.541, 0.235, 0.224, '["微博", "新浪新闻", "澎湃新闻", "知乎"]', '而争议不只这一点，比赛第58分钟时，埃及队反击破门一度将比分扩大至2-0，但事后主裁判经VAR判定有埃及队球员此前对利马犯规在先，因此进球无效。但埃及球员疯狂抗议：在阿根廷发动这次反击之前，萨拉赫在另一端被犯规倒地，裁判没有吹停比赛，球权直接到了阿根廷脚下。以下是埃及队的犯规获利时间表：00：25埃及球员被断球后撞恩佐膝盖，裁判没有表示（危险动作）2：28麦卡利斯特无球状态下遭埃及球员冲撞2：29梅西持球遭埃及防守球员拉拽2：33梅西传球在埃及球员推搡干扰下传出界外5：47埃及防守球员发力推德保罗22：18埃及防守球员发力推梅西26：41埃及防守球员推搡恩佐34：54埃及防守球员用力推搡小蜘蛛35：51埃及防守球员用力推搡帕雷德斯36：15德保罗弧顶处无球状态下被埃及防守球员撕扯衣服倒地36：44埃及球员冲撞帕雷德斯致其倒地36：45梅西背身遭埃及防守球员冲撞推搡导致丢失球权，裁判没有任何表示41：40埃及球员无球状态下禁区内推搡阿尔瓦雷斯42：06埃及防守球员在弧顶处分别推搡恩佐和梅西49：26防守球员背身冲撞梅西46：48梅西带球推进遭埃及防守球员拉拽46：52麦卡利斯特背身做球被埃及防守球员拉倒54：30恩佐背身护球遭到埃及防守球员拉拽61：47麦卡利斯特被推倒埃及顺势打反击 裁判没有表示63：13麦卡利斯特向前带球推进被身后拉拽63：30萨拉赫对利马犯规阿根廷进攻有利被吹64：22梅西追球遭背后埃及防守球员拉拽74：25埃及队门将故意拖延时间不开球79：56梅西寻求撞墙，埃及防守球员抬臂阻挡梅西81：42埃及防守球员被梅西突破后伸手拉拽85：24埃及防守球员背后发力推恩佐88：01小蜘蛛持球后埃及防守球员上前拉拽99：37恩佐护球埃及防守球员拉拽且恶意冲撞恩佐100：20劳马护球埃及防守球员搂抱且另一名埃及队员主动挑衅。', '埃及、瑞士、法国', '#阿根廷vs埃及##裁判 偏心# 埃及是真的牛B啊，真的太牛B了，直接二比零阿根廷，阿根廷踢球是真脏。', '["萨拉", "科里纳", "哈桑", "恩佐", "孙葆洁"]', '{"credibility_score": 0.397, "official_ratio": 0.187, "verified_ratio": 0.6, "plain_user_ratio": 0.4, "verification_dist": {"普通用户": 0.4, "认证个人": 0.28, "官方平台": 0.187, "认证机构": 0.08, "头部认证个人": 0.053}, "factors": []}', '{"key_nodes": [{"role": "首次大V发声", "author": "直播吧", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-08T02:14:19", "influence": 3959.9, "title": "埃及全队投诉，阿根廷进球前，萨拉赫在阿根廷禁区倒地，埃及工作人员被红牌罚下。主帅"}, {"role": "初始爆料", "author": "雷速体育", "platform": "知乎", "verification_type": "普通用户", "publish_time"