INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (7, '世界杯首次1/16决赛，我们看什么？_运动家_澎湃新闻-The Paper', 5.166, 49, 0, '2026-06-03 08:29:10', '2026-07-12 22:16:22', '2026-07-10 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.455, 0.273, 0.273, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '国际足联发布声明，允许巴洛贡继续出战与比利时队的1/8决赛 按FIFA的说法，美国队前锋巴洛贡因在世界杯1/16决赛对阵波黑队时踩踏对方球员被禁赛一场。但事实上，从国际足联对美国队红牌球员史无前例的“特赦”，到法国与巴拉圭、阿根廷与埃及比赛中的判罚争议，本届世界杯开赛至今，不断出现的“场外因素”不仅已经严重影响到了球迷的观感，还侵蚀着体育精神的纯粹与本真。美加墨世界杯欧洲6席，分别为法国、英格兰、比利时、西班牙、挪威和瑞士，南美仅剩阿根廷，非洲仍由摩洛哥占据一席。', '美加墨、埃及、比利时', '世界杯大名单的争议--文旅·体育--人民网。', '["蒂诺", "梅里", "萨拉", "罗梅罗", "洛特"]', '{"credibility_score": 0.815, "official_ratio": 0.776, "verified_ratio": 0.816, "plain_user_ratio": 0.184, "verification_dist": {"官方平台": 0.776, "普通用户": 0.184, "认证机构": 0.02, "认证个人": 0.02}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "新华社", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-06-03T08:29:10", "influence": 0.0, "title": "世界杯大名单的争议--文旅·体育--人民网"}, {"role": "初始爆料", "author": "耶路撒冷饮", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-06-30T17:25:37", "influence": 43.9, "title": "马赫雷斯赛后接受采访时，为93分钟射进的那一球的解释是：“最后时刻有人把球传进禁"}, {"role": "首次大V发声", "author": "咪咕足球", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-04T08:44:49", "influence": 11619.5, "title": "#阿根廷16强# 2026世界杯1/16决赛，卫冕冠军阿根廷3-2力克佛得角，晋"}], "top_influencers": [{"author": "咪咕足球", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-04T08:44:49", "influence": 11619.5, "repost_count": 1561, "like_count": 30275, "comment_count": 1952, "title": "#阿根廷16强# 2026世界杯1/16决赛，卫冕冠军阿根廷3-2力克佛得角，晋"}, {"author": "门东喵的蛋挞", "platform": "知乎", "verification_type": "认证个人", "publish_time": "2026-07-11T14:02:18", "influence": 82.5, "repost_count": 0, "like_count": 220, "comment_count": 33, "title": "先说结论：FIFA不是一个公平公正的组织，这次美加墨世界杯分组抽签直接就把保送C"}, {"author": "耶路撒冷饮", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-06-30T17:25:37", "influence": 43.9, "repost_count": 0, "like_count": 118, "comment_count": 17, "title": "马赫雷斯赛后接受采访时，为93分钟射进的那一球的解释是：“最后时刻有人把球传进禁"}, {"author": "厉无咎", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-10T16:27:19", "influence": 9.9, "repost_count": 0, "like_count": 33, "comment_count": 0, "title": "埃及球员怒喷裁判不公正称世界杯被内定，大量球迷吐槽阿根廷脏，这场裁判真的有问题吗"}, {"author": "汴良", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-10T16:40:47", "influence": 1.8, "repost_count": 0, "like_count": 6, "comment_count": 0, "title": "2026年7月第一周，世界杯1/8决赛。埃及输给阿根廷后，埃及主帅怒喷国际足联："}], "platform_chain": {"nodes": [{"name": "人民网", "count": 3, "first_seen": "2026-06-03T08:29:10"}, {"name": "澎湃新闻", "count": 31, "first_seen": "2026-06-28T00:00:00"}, {"name": "知乎", "count": 9, "first_seen": "2026-06-30T17:25:37"}, {"name": "微博", "count": 2, "first_seen": "2026-07-04T08:44:49"}, {"name": "新浪新闻", "count": 4, "first_seen": "2026-07-09T14:07:00"}], "links": [{"source": "人民网", "target": "澎湃新闻", "value": 31}, {"source": "澎湃新闻", "target": "知乎", "value": 9}, {"source": "知乎", "target": "微博", "value": 2}, {"source": "微博", "target": "新浪新闻", "value": 4}]}}', '2026-07-13 19:10:32', '2026-07-13 19:10:32');
