INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (12, '第1现场｜无人机直击：六蓝水库附近村庄遭洪水侵袭_快看_澎湃新闻-The Paper', 25.717, 106, 0, '2026-06-01 08:59:41', '2026-07-12 22:09:40', '2026-07-12 12:00:00', 'mid_high', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.464, 0.321, 0.214, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '时隔近半个世纪，北京陆续启动5座山区防洪水库规划建设——在永定河、拒马河、大石河、温榆河上游，规划建设永定河官厅山峡洪水控制工程、拒马河张坊洪水控制工程、二道河水库、钻子岭水库、西峰山水库。全市水库库容将达到100亿立方米 市水务局水利工程建设处处长樊斌介绍，按照“上蓄、中疏、下排、有效治洪”的原则，北京市全面推动防洪基础设施建设。从洞庭湖畔的千里堤防到闽江下游的防洪大堤，从龙山水库的土石坝到南水北调的宏伟工程，从黄土高原的淤地坝到华南丘陵的中型水库，探地雷达正以它独特的方式，为一座又一座大坝做着无声的“体检”。', '广西、横州、台风', '广西贵港抽水蓄能电站全面开工。', '["美莎克", "梁平", "邓剑洋", "陆绍相", "段朝达"]', '{"credibility_score": 0.642, "official_ratio": 0.528, "verified_ratio": 0.736, "plain_user_ratio": 0.264, "verification_dist": {"官方平台": 0.528, "普通用户": 0.264, "认证个人": 0.132, "认证机构": 0.038, "头部认证个人": 0.038}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "人民网-图片频道", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-06-01T08:59:41.000001", "influence": 0.0, "title": "湖南江华：水库风光美--图片频道--人民网"}, {"role": "首次大V发声", "author": "新浪热点", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-06T14:32:31", "influence": 274.5, "title": "#广西贵港辟谣两水库崩堤溃漏#【广西贵港：网传达开水库、石牛水库“崩堤溃漏”系谣"}, {"role": "初始爆料", "author": "波动科技", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-07T10:54:14.999999", "influence": 0.3, "title": "广西六蓝水库溃坝之后：探地雷达如何为9.8万座大坝筑牢“看不见的防线”？ - 知"}, {"role": "传播高峰", "author": "央视新闻", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-09T12:37:54", "influence": 651.0, "title": "【#六蓝水库洪灾已致26死亡#】#广西洪灾已致39人遇难# 今天，#广西南宁防汛"}], "top_influencers": [{"auth