INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (13, '广西横州无人机协会披露无人机吊人救援细节：吊起2人神图系AI合成_直击现场_澎湃新闻-The Paper', 10.964, 30, 0, '2026-07-07 23:30:38', '2026-07-12 21:00:00', '2026-07-12 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.6, 0.333, 0.067, '["微博", "新浪新闻", "澎湃新闻", "知乎"]', '谈到网上那张救援人员和群众被无人机同时吊起的“神图”，梁为磊说，图片是AI生成的，但无人机一次吊起两个人并非不可能，只是因为风险较高，在横州地区尚未尝试过。浑浊洪水漫过一楼、淹没道路、冲断桥梁，村庄成孤岛，车辆困洪流，冲锋舟受湍急水流、电线阻拦无法靠近被困群众，一条震撼全网的救援视频，道尽最朴素的道理：规则是底线，生命是上限，原则上无人机严禁吊人，但危急关头，人民永远大于冰冷条文。如果死守 “无人机绝对不能吊人” 这条死板原则，眼睁睁看着被困群众困在洪水孤岛、等不到舟艇救援，错失黄金逃生时间，那规则就失去了存在的意义。', '广西、贵港、横州', '洪水过境贵港故土：见过无常，才懂平安是此生最大的福报 - 知乎。', '["美莎克", "陆军"]', '{"credibility_score": 0.53, "official_ratio": 0.4, "verified_ratio": 0.6, "plain_user_ratio": 0.4, "verification_dist": {"官方平台": 0.4, "普通用户": 0.4, "认证个人": 0.133, "认证机构": 0.067}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "初始爆料", "author": "渡川见心", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-07T23:30:38.000001", "influence": 0.0, "title": "洪水过境贵港故土：见过无常，才懂平安是此生最大的福报 - 知乎"}, {"role": "首次官方媒体介入", "author": "爆闻速递小哥", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-10T07:36:46", "influence": 0.0, "title": "广西暴雨超8000人抗洪救援"}, {"role": "传播高峰", "author": "大又元", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-11T09:12:10", "influence": 385.0, "title": "命运反复出题，而你给出的答案一次比一次震撼！这个构图绝了，原则上无人机不能载人，"}, {"role": "首次大V发声", "author": "南宁融媒", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-12T18:02:00", "influence": 0.0, "title": "受台风“美莎克”影响，7月4日以来，南宁市出现了历史罕见的大范围持续性强降雨。7"}], "top_influencers": [{"author": "大又元", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-11T09:12:10", "influence": 385.0, "repost_count": 0, "like_count": 1070, "comment_count": 128, "title": "命运反复出题，而你给出的答案一次比一次震撼！这个构图绝了，原则上无人机不能载人，"}, {"author": "金错刀", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-12T09:27:49", "influence": 71.8, "repost_count": 0, "like_count": 196, "comment_count": 26, "title": "“主动塌房”的无人机，在广西洪灾中一夜封神 - 知乎"}, {"author": "躺赢板", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-11T12:03:28", "influence": 45.0, "repost_count": 3, "like_count": 110, "comment_count": 18, "title": "很心疼，知道价格之后更心疼了 ，那些在广西洪水里吊人救命的无人机，最便宜的五万多"}, {"author": "旅行厨男", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-12T14:19:36", "influence": 32.1, "repost_count": 6, "like_count": 77, "comment_count": 6, "title": "广西贵港，一位抗洪军人在救援途中偶遇自己的妻儿被救！[作揖][心][good]["}, {"author": "枫冷慕诗", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-11T12:21:56", "influence": 31.1, "repost_count": 0, "like_count": 92, "comment_count": 7, "title": "因为用无人设备了，这次广西的洪水里，科技为人类开出了一条条逃生之路，当救援的冲锋"}], "platform_chain": {"nodes": [{"name": "知乎", "count": 12, "first_seen": "2026-07-07T23:30:38.000001"}, {"name": "新浪新闻", "count": 11, "first_seen": "2026-07-10T07:36:46"}, {"name": "澎湃新闻", "count": 1, "first_seen": "2026-07-11T10:56:00"}, {"name": "微博", "count": 6, "first_seen": "2026-07-11T12:03:28"}], "links": [{"source": "知乎", "target": "新浪新闻", "value": 11}, {"source": "新浪新闻", "target": "澎湃新闻", "value": 1}, {"source": "澎湃新闻", "target": "微博", "value": 6}]}}', '2026-07-13 19:10:32', '2026-07-13 19:10:32');
