INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (18, '湛江辟谣“全市停水”：台风“麦德姆”致个别小区用水受影响_直击现场_澎湃新闻-The Paper', 5.101, 56, 0, '2026-06-04 16:50:38', '2026-07-12 21:47:38', '2026-07-12 12:00:00', 'mid', 'growth', 0.9, 0.05, 0.9, 0.05, 0.0, '当前事件报道数量持续增加，公众关注度快速提升，处于成长期。', 0.427, 0.379, 0.194, '["人民网", "微博", "澎湃新闻", "知乎"]', '自治区水文中心预测，未来12小时，都柳江三江侗族自治县洋溪乡河段将复涨，并再次出现超警戒水位3.5米左右洪水，柳江柳州市城区河段将出现83.2米左右的洪峰水位。受今年第10号台风“美莎克”影响，7月5日8时至6日8时，广西中部南部降暴雨到大暴雨、局部特大暴雨，广西郁江及支流镇龙江东班江、西江支流马来河、桂南沿海防城河等53条河流发生超警以上洪水，其中镇龙江、东班江、马来河、防城河等4条中小河流发生有实测资料以来最大洪水，个别水库出现重大险情。据预报，未来2天广西东南部和北部仍将有大暴雨，西江干流及支流柳江桂江可能发生超警洪水，支流郁江维持超警，防汛形势异常严峻。', '广西、贵港、台风', '广西升级发布洪水黄色预警。', '["美莎克", "黄淮", "麦德姆", "武思江", "覃塘区"]', '{"credibility_score": 0.914, "official_ratio": 0.893, "verified_ratio": 0.929, "plain_user_ratio": 0.071, "verification_dist": {"官方平台": 0.893, "普通用户": 0.071, "头部认证个人": 0.018, "认证个人": 0.018}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "人民网－广西频道", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-06-04T16:50:38", "influence": 0.0, "title": "贵港供电局全力筑牢高考保电安全防线"}, {"role": "初始爆料", "author": "胡飞飞", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-06T15:43:34", "influence": 0.3, "title": "广西郁江发生2026年第1号洪水，贵港水文站水位超警戒1.80米 - 知乎"}, {"role": "传播高峰", "author": "祥昊", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-10T11:04:24", "influence": 53.4, "title": "先说坏消息。沙糖桔作为宽皮柑橘，确实非常怕涝。由于它的根系以好气性须根为主，呼吸"}, {"role": "首次大V发声", "author": "是幸运的千问哇", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-12T20:52:55.000001", "influence": 3.3, "title": "#台风美莎克#警惕！受台风“美莎克”残余环流影响，广西多地正遭遇历史罕见的持续性"}], "top_influencers": [{"author": "祥昊", "p