INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (30, '国际油价仍未挣脱“海峡困局”--经济·科技--人民网', 2.415, 15, 0, '2026-06-09 09:36:33', '2026-07-12 20:12:53', '2026-07-10 12:00:00', 'low', 'peak', 0.9, 0.0, 0.05, 0.9, 0.05, '当前事件报道量已接近峰值，关注度趋于稳定，处于高潮期。', 0.619, 0.19, 0.19, '["人民网", "微博", "新浪新闻", "知乎"]', '国际油价因地缘政治风险剧烈震荡，伦敦布伦特原油价格最高飙升到114美元/桶，全球能源市场也因此陷入“海峡困局”。国际评级机构惠誉维持2026年布伦特原油全年87美元/桶的均价基准，不过，该机构将今年四季度油价预期下调到70美元/桶至73美元/桶，前提是伊朗原油出口持续放量、石油输出国组织（欧佩克）与非欧佩克产油国组成的“欧佩克+”灵活释放闲置产能。这一次美伊冲突拉动油价，油价的短期冲高重新激活了通胀担忧，通胀担忧又强化了加息预期——黄金被压下去，不是矛盾，而是非常符合逻辑的结果。', '霍尔木兹海峡、美伊、中东', '#油价存在失控风险#【中金财富期货：目前黄金市场在流动性短缺和通胀压力的双重挤压下，参与价值有限】#。', '["布伦特"]', '{"credibility_score": 0.463, "official_ratio": 0.2, "verified_ratio": 0.6, "plain_user_ratio": 0.4, "verification_dist": {"普通用户": 0.4, "官方平台": 0.2, "认证机构": 0.2, "认证个人": 0.133, "头部认证个人": 0.067}, "factors": []}', '{"key_nodes": [{"role": "首次大V发声", "author": "新浪财经", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-06-09T09:36:33", "influence": 80.3, "title": "#油价存在失控风险#【中金财富期货：目前黄金市场在流动性短缺和通胀压力的双重挤压"}, {"role": "首次官方媒体介入", "author": "经济日报", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-07-03T09:02:47", "influence": 0.0, "title": "国际油价仍未挣脱“海峡困局”--经济·科技--人民网"}, {"role": "初始爆料", "author": "木已断水", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-03T21:12:34", "influence": 1.5, "title": "之前大战爆发的时候，就已经分析了，石油下跌后的利好品种。再系统梳理下，利好品种内"}, {"role": "传播高峰", "author": "波浪理论学习", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-10T12:02:38", "influence": 93.0, "title": "#黄金##XAU# 这次上涨是第一部分，随后的下跌是第二部分，调整还在进行，不是"}], "top_influencers": [{"author": "波浪理论学习", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-10T12:02:38", "influence": 93.0, "repost_count": 1, "like_count": 225, "comment_count": 49, "title": "#黄金##XAU# 这次上涨是第一部分，随后的下跌是第二部分，调整还在进行，不是"}, {"author": "新浪财经", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-06-09T09:36:33", "influence": 80.3, "repost_count": 28, "like_count": 126, "comment_count": 29, "title": "#油价存在失控风险#【中金财富期货：目前黄金市场在流动性短缺和通胀压力的双重挤压"}, {"author": "秦永臣DXY", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-04T07:41:20", "influence": 62.8, "repost_count": 4, "like_count": 136, "comment_count": 36, "title": "不要豪赌油价 我之前在评论原油和黄金都下跌的情况下，买金还是买油的问题时，明确说"}, {"author": "波段猎手阿福", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-10T07:13:14", "influence": 23.9, "repost_count": 2, "like_count": 58, "comment_count": 9, "title": "黄金原油下跌"}, {"author": "财联社APP", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-08T16:19:24", "influence": 10.3, "repost_count": 2, "like_count": 26, "comment_count": 1, "title": "【#国际油价又飙升# #金银再度急跌#】财联社7月8日电，布伦特原油期货涨幅扩大"}], "platform_chain": {"nodes": [{"name": "微博", "count": 6, "first_seen": "2026-06-09T09:36:33"}, {"name": "人民网", "count": 1, "first_seen": "2026-07-03T09:02:47"}, {"name": "知乎", "count": 6, "first_seen": "2026-07-03T21:12:34"}, {"name": "新浪新闻", "count": 2, "first_seen": "2026-07-09T11:14:40"}], "links": [{"source": "微博", "target": "人民网", "value": 1}, {"source": "人民网", "target": "知乎", "value": 6}, {"source": "知乎", "target": "新浪新闻", "value": 2}]}}', '2026-07-13 19:10:32', '2026-07-13 19:10:32');
